import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as t,d as n}from"./app-75fed8c6.js";const s={},d=n(`<h2 id="目录结构" tabindex="-1"><a class="header-anchor" href="#目录结构" aria-hidden="true">#</a> 目录结构</h2><table><thead><tr><th style="text-align:left;">目录</th><th style="text-align:center;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">/</td><td style="text-align:center;">根目录</td></tr><tr><td style="text-align:left;">/bin</td><td style="text-align:center;">普通的基本命令，如 ls、chmod 等，一般的用户也都可以使用</td></tr><tr><td style="text-align:left;">/boot</td><td style="text-align:center;">这里存放的是启动 Linux 时使用的一些核心文件，启动目录，启动相关文件</td></tr><tr><td style="text-align:left;">/dev</td><td style="text-align:center;">该目录下存放的是 Linux 的外部设备，在 Linux 中访问设备的方式和访问文件的方式是相同的</td></tr><tr><td style="text-align:left;">/etc</td><td style="text-align:center;">存放所有的系统管理所需要的配置文件和子目录</td></tr><tr><td style="text-align:left;">/home</td><td style="text-align:center;">普通用户的家目录，可以操作</td></tr><tr><td style="text-align:left;">/lib</td><td style="text-align:center;">系统库保存目录</td></tr><tr><td style="text-align:left;">/media</td><td style="text-align:center;">U 盘、光驱等等，当识别后，Linux 会把识别的设备挂载到这个目录下</td></tr><tr><td style="text-align:left;">/mnt</td><td style="text-align:center;">移动设备挂载目录</td></tr><tr><td style="text-align:left;">/opt</td><td style="text-align:center;">这是给主机额外安装软件所摆放的目录。比如你安装一个 ORACLE 数据库则就可以放到这个目录下,默认是空的</td></tr><tr><td style="text-align:left;">/proc</td><td style="text-align:center;">正在运行的内核信息映射、主要输出进行信息、内存资源信息和磁盘分析信息等</td></tr><tr><td style="text-align:left;">/root</td><td style="text-align:center;">超级用户的家目录，可以操作</td></tr><tr><td style="text-align:left;">/sbin</td><td style="text-align:center;">基本的系统命令，如 shutdown、reboot，用于启动系统，只有管理员才可以运行</td></tr><tr><td style="text-align:left;">/sys</td><td style="text-align:center;">系统设备等驱动程序信息</td></tr><tr><td style="text-align:left;">/tmp</td><td style="text-align:center;">临时目录，可以操作</td></tr><tr><td style="text-align:left;">/user/bin</td><td style="text-align:center;">是你在后期安装的一些软件的运行脚本</td></tr><tr><td style="text-align:left;">/user/sbin</td><td style="text-align:center;">放置一些用户安装的系统管理的必备程序</td></tr><tr><td style="text-align:left;">/var</td><td style="text-align:center;">这个目录中存放着在不断扩充着的东西，我们习惯将那些经常被修改的目录放在这个目录下。包括各种日志文件</td></tr></tbody></table><h2 id="命令基本格式" tabindex="-1"><a class="header-anchor" href="#命令基本格式" aria-hidden="true">#</a> 命令基本格式</h2><h3 id="命令提示符" tabindex="-1"><a class="header-anchor" href="#命令提示符" aria-hidden="true">#</a> 命令提示符</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment">#</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>root 当前用户</li><li>localhost 当前主机名</li><li>~当前用户的家目录</li><li>提示符 超级用户是#，普通用户是$</li></ul><h3 id="命令格式" tabindex="-1"><a class="header-anchor" href="#命令格式" aria-hidden="true">#</a> 命令格式</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>命令 选项 参数
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>命令 [选项][参数]</li><li>当有多个选项时，可以写在一起</li><li>一般参数有简化和完整两种写法</li></ul><h2 id="关机和重启命令" tabindex="-1"><a class="header-anchor" href="#关机和重启命令" aria-hidden="true">#</a> 关机和重启命令</h2><h3 id="shutdown" tabindex="-1"><a class="header-anchor" href="#shutdown" aria-hidden="true">#</a> shutdown</h3><p>可以用来进行关机程序，并且在关机以前传送讯息给所有使用者正在执行的程序，shutdown 也可以用来重开机。</p><p>使用权限：系统管理者。</p><h4 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">shutdown</span> <span class="token punctuation">[</span>-t seconds<span class="token punctuation">]</span> <span class="token punctuation">[</span>-rkhncfF<span class="token punctuation">]</span> <span class="token function">time</span> <span class="token punctuation">[</span>message<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-t seconds</code>: 设定在几秒钟之后进行关机程序。</li><li><code>-k</code>: 并不会真的关机，只是将警告讯息传送给所有使用者。</li><li><code>-r</code>: 关机后重新开机。</li><li><code>-h</code>: 关机后停机。</li><li><code>-n</code>: 不采用正常程序来关机，用强迫的方式杀掉所有执行中的程序后自行关机。</li><li><code>-c</code>: 取消目前已经进行中的关机动作。</li><li><code>-f</code>: 关机时，不做 fsck 动作(检查 Linux 档系统)。</li><li><code>-F</code>: 关机时，强迫进行 fsck 动作。</li><li><code>time</code>: 设定关机的时间。</li><li><code>message</code>: 传送给所有使用者的警告讯息。</li></ul><h4 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h4><p>立即关机</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">shutdown</span> <span class="token parameter variable">-h</span> now
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>指定 10 分钟后关机</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">shutdown</span> <span class="token parameter variable">-h</span> <span class="token number">10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重新启动计算机</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">shutdown</span> <span class="token parameter variable">-r</span> now
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="reboot" tabindex="-1"><a class="header-anchor" href="#reboot" aria-hidden="true">#</a> reboot</h3><p>用于用来重新启动计算机。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">reboot</span> <span class="token punctuation">[</span>-n<span class="token punctuation">]</span> <span class="token punctuation">[</span>-w<span class="token punctuation">]</span> <span class="token punctuation">[</span>-d<span class="token punctuation">]</span> <span class="token punctuation">[</span>-f<span class="token punctuation">]</span> <span class="token punctuation">[</span>-i<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-n</code>: 在重开机前不做将记忆体资料写回硬盘的动作</li><li><code>-w</code>: 并不会真的重开机，只是把记录写到 /var/log/wtmp 档案里</li><li><code>-d</code>: 不把记录写到 /var/log/wtmp 档案里（-n 这个参数包含了 -d）</li><li><code>-f</code>: 强迫重开机，不呼叫 shutdown 这个指令</li><li><code>-i</code>: 在重开机之前先把所有网络相关的装置先停止</li></ul><h4 id="实例-1" tabindex="-1"><a class="header-anchor" href="#实例-1" aria-hidden="true">#</a> 实例</h4><p>重新启动</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">reboot</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="语法-1" tabindex="-1"><a class="header-anchor" href="#语法-1" aria-hidden="true">#</a> 语法</h4><h2 id="登录与退出" tabindex="-1"><a class="header-anchor" href="#登录与退出" aria-hidden="true">#</a> 登录与退出</h2><h3 id="logout" tabindex="-1"><a class="header-anchor" href="#logout" aria-hidden="true">#</a> logout</h3><p>用于退出系统。</p><h4 id="语法-2" tabindex="-1"><a class="header-anchor" href="#语法-2" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">logout</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="login" tabindex="-1"><a class="header-anchor" href="#login" aria-hidden="true">#</a> login</h3><p>用于登入系统</p><h4 id="语法-3" tabindex="-1"><a class="header-anchor" href="#语法-3" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>login
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="who" tabindex="-1"><a class="header-anchor" href="#who" aria-hidden="true">#</a> who</h3><p>用于显示系统中有哪些使用者正在上面，显示的资料包含了使用者 ID、使用的终端机、从哪边连上来的、上线时间、呆滞时间、CPU 使用量、动作等等。</p><p>使用权限：所有使用者都可使用。</p><h4 id="语法-4" tabindex="-1"><a class="header-anchor" href="#语法-4" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">who</span> - <span class="token punctuation">[</span>husfV<span class="token punctuation">]</span> <span class="token punctuation">[</span>user<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-H</code>或<code>--heading</code>：显示各栏位的标题信息列；</li><li><code>-i</code>或<code>-u</code>或<code>--idle</code>：显示闲置时间，若该用户在前一分钟之内有进行任何动作，将标示成&quot;.&quot;号，如果该用户已超过24小时没有任何动作，则标示出&quot;old&quot;字符串；</li><li><code>-m</code>：此参数的效果和指定&quot;am i&quot;字符串相同；</li><li><code>-q</code>或<code>--count</code>：只显示登入系统的帐号名称和总人数；</li><li><code>-s</code>：此参数将忽略不予处理，仅负责解决who指令其他版本的兼容性问题；</li><li><code>-w</code>或<code>-T</code>或<code>--mesg</code>或<code>--message</code>或<code>--writable</code>：显示用户的信息状态栏；</li><li><code>--help</code>：在线帮助；</li><li><code>--version</code>：显示版本信息。</li></ul><h4 id="实例-2" tabindex="-1"><a class="header-anchor" href="#实例-2" aria-hidden="true">#</a> 实例</h4><p>显示当前登录系统的用户</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">who</span>  //显示当前登录系统的用户
<span class="token comment"># root   tty7     2014-05-13 12:12 (:0)</span>
<span class="token comment"># root   pts/0    2014-05-14 17:09 (:0.0)</span>
<span class="token comment"># root   pts/1    2014-05-14 18:51 (192.168.1.17)</span>
<span class="token comment"># root   pts/2    2014-05-14 19:48 (192.168.1.17)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,49),i=[d];function l(c,o){return a(),t("div",null,i)}const u=e(s,[["render",l],["__file","02.基础.html.vue"]]);export{u as default};
